update public.community_template_items set
  name_en = coalesce(nullif(name_en,''), name),
  note_en = coalesce(note_en, note),
  tags_zh = coalesce(tags_zh, '{}'),
  tags_en = coalesce(tags_en, '{}');

update public.community_template_items i
set
  name_zh = v.name_zh,
  name_en = coalesce(nullif(i.name_en,''), v.name_en),
  note_zh = coalesce(i.note_zh, v.note_zh),
  note_en = coalesce(i.note_en, v.note_en),
  tags_zh = case when coalesce(array_length(i.tags_zh,1),0)=0 then v.tags_zh::text[] else i.tags_zh end,
  tags_en = case when coalesce(array_length(i.tags_en,1),0)=0 then v.tags_en::text[] else i.tags_en end
